#!/bin/bash
hyprctl monitors -j | jq -r 'map(. + {eff_w: (if . transform % 2 != 0 then . height else .width end), eff_h: (if .transform % 2 != 0 then .width else .height end)}) | (map(.x) | min) as $min_x | (map(.y) | min) as $min_y | (map(. x + .eff_w) | max) as $max_x | (map(. y + .eff_h) | max) as $max_y | map(. + {norm_x: (.x - $min_x), norm_y: (.y - $min_y)}) | (map(select(.norm_x == 0 and .norm_y == 0)) | first // first) as $anchor | ($max_x - $min_x) as $width | ($max_y - $min_y) as $height | "monitor:  \($anchor.name) | move: \(-$anchor.norm_x),\(-$anchor.norm_y) | size: \($width)x\($height)"'
